CREATE TABLE IF NOT EXISTS geo_drafts (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id UUID NOT NULL, query_id UUID, title TEXT NOT NULL, content_md TEXT NOT NULL DEFAULT '', target_keywords TEXT[] DEFAULT ARRAY[]::TEXT[], status TEXT NOT NULL DEFAULT 'draft', model TEXT, word_count INT DEFAULT 0, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW());